SELECT /* AppMapper.selectUsrAppDetail */ a.UUID, a.USER_ID, a.UDID, a.OS, a.VERSION, a.SEND_YN, a.APP_OS_VER, a.APP_NM, a.LAST_ACCESS_DT, a.BADGE_CNT, a.AUTO_LOGIN_YN as simpleLoginYn, a.BIO_LOGIN_YN, a.WDGT_USE_QNTY_CALL_CYCL_CD, a.CRET_ID, a.UP_ID, b.TOKEN, b.TOKEN_REG_DT, b.TOKEN_VALID_PERIOD, a.SEND_YN_REFERER, a.SEND_YN_UP_DT FROM NMCP_USR_APP_INFO a, NMCP_AUTO_LOGIN_TXN b WHERE 1=1 AND a.USER_ID = b.USER_ID(+)
AND a.UUID = #{uuid}
AND b.TOKEN = #{token}
AND a.USER_ID = #{userId}
ORDER BY a.UP_DT DESC

