mapper.update:
	MERGE INTO NMCP_USR_APP_INFO USING DUAL ON (UUID = #{uuid})
		WHEN MATCHED THEN
			UPDATE SET
				UP_DT = SYSDATE

		        , UDID = #{udid}


               	, UP_ID = #{userId}


				,  USER_ID = #{userId}


	        	, VERSION = #{version}


				, OS = #{os}


	        	, SEND_YN = #{sendYn}


                , APP_OS_VER = #{appOsVer}


                , APP_NM = #{appNm}


                , BADGE_CNT = #{badgeCnt}


	        	, AUTO_LOGIN_YN = #{simpleLoginYn}


				, BIO_LOGIN_YN = #{bioLoginYn}


				, WDGT_USE_QNTY_CALL_CYCL_CD = #{wdgtUseQntyCallCyclCd}

                , LAST_ACCESS_DT = SYSDATE
		WHEN NOT MATCHED THEN
			INSERT (
	             	  UUID

	               	, USER_ID

	             	, UDID
	             	, OS
	             	, VERSION
		        	, SEND_YN
	             	, CRET_DT
	             	, CRET_ID
	             	, UP_DT
	             	, UP_ID
	                , APP_OS_VER
	                , APP_NM
	                , LAST_ACCESS_DT
	                , BADGE_CNT
	                , AUTO_LOGIN_YN
	                , BIO_LOGIN_YN
	                , WDGT_USE_QNTY_CALL_CYCL_CD
	        )
			VALUES
			(
				 	  #{uuid}

					, #{userId}

	             	, #{udid}
	             	, #{os}
	             	, #{version}
	             	, 'Y'
	             	, SYSDATE
	             	, #{userId}
	             	, SYSDATE
	             	, #{userId}
	             	, #{appOsVer}
	             	, #{appNm}
	             	, SYSDATE
	             	, #{badgeCnt}
	             	, 'N'
	             	, 'N'
	             	, #{wdgtUseQntyCallCyclCd}
	      )
